patch:
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 275b3d567856..3d621d3fb2e7 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7374,7 +7374,12 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
     return any_of(*BB, [&SeenInstrs, &CostCtx, TheLoop, BB](Instruction &I) {
       if (isa<PHINode>(&I) && BB == TheLoop->getHeader())
         return false;
-      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
+      // If the instruction is either not represented in the VPlan or is
+      // skipped by the VPlan-based cost computations, this indicates extra
+      // simplifications performed by VPlan compared to the legacy model.
+      if (!SeenInstrs.contains(&I) || CostCtx.skipCostComputation(&I, true))
+        return true;
+      return false;
     });
   });
 }

