diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 275b3d567856..34dd3883bbc6 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7374,7 +7374,11 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
     return any_of(*BB, [&SeenInstrs, &CostCtx, TheLoop, BB](Instruction &I) {
       if (isa<PHINode>(&I) && BB == TheLoop->getHeader())
         return false;
-      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
+      // If the instruction is not represented in the VPlan and either not
+      // skipped by the cost context or is loop-invariant (which VPlan may
+      // hoist or otherwise simplify), treat it as an additional simplification.
+      return !SeenInstrs.contains(&I) &&
+             (!CostCtx.skipCostComputation(&I, true) || TheLoop->isLoopInvariant(&I));
     });
   });
 }
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 275b3d567856..c1a309c2fdce 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7374,7 +7374,28 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
     return any_of(*BB, [&SeenInstrs, &CostCtx, TheLoop, BB](Instruction &I) {
       if (isa<PHINode>(&I) && BB == TheLoop->getHeader())
         return false;
-      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
+      // If the instruction is not represented in the VPlan and either not
+      // skipped by the cost context, or is uniform/hoistable, treat it as an
+      // additional simplification. Loads with loop-invariant pointers are
+      // considered uniform by VPlan and may be hoisted/broadcasted.
+      if (!SeenInstrs.contains(&I)) {
+        if (!CostCtx.skipCostComputation(&I, true))
+          return true;
+        // Consider a skipped load with loop-invariant pointer as additional
+        // simplification, even if the load itself isn't loop-invariant.
+        if (auto *LI = dyn_cast<LoadInst>(&I)) {
+          Value *Ptr = LI->getPointerOperand();
+          if (TheLoop->isLoopInvariant(Ptr))
+            return true;
+        }
+        // Also consider other instructions whose operands are all
+        // loop-invariant, which VPlan may treat as uniform and simplify.
+        if (all_of(I.operands(), [TheLoop](Value *Op) {
+              return TheLoop->isLoopInvariant(Op);
+            }))
+          return true;
+      }
+      return false;
     });
   });
 }
